  ('generalpolice-94737317-moex-00490', 'generalpolice-94737317', 'generalpolice-94737317-moex-111-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一根圓柱形的金屬棒，長度為L、半徑為r。該金屬的電阻率為ρ，而電阻為R。金屬棒的電阻和長 度成正比，而與截面積A成反比（A＝r2）。如果將該金屬棒均勻地拉長為3L，且形狀保持為圓柱 形，拉長以後的金屬棒之電阻變為多少？ 1', '["R", "3R", "9R", "仍是R 9"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:48+00:00", "source_pdf_sha1": "46a94943e2b1", "answer_pdf_sha1": "4509f4bde46a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "402", "s": "1606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
